import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import { useCart } from '../context/CartContext';

const FALLBACK_IMAGES = {
  Electronics: 'https://images.unsplash.com/photo-1498049794561-7780e7231661?w=400',
  Shoes: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400',
  Clothing: 'https://images.unsplash.com/photo-1523381210434-271e8be1f52b?w=400',
  Books: 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=400',
  Beauty: 'https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=400',
  Sports: 'https://images.unsplash.com/photo-1517649763962-0c623066013b?w=400',
  Home: 'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?w=400',
  default: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=400',
};

const BANNERS = [
  { title: '🔥 Big Electronics Sale', sub: 'Up to 40% off on top brands', bg: 'linear-gradient(135deg, #0f3460, #16213e)', btn: 'Shop Electronics', cat: 'Electronics' },
  { title: '👟 New Arrivals in Shoes', sub: 'Step into style this season', bg: 'linear-gradient(135deg, #e94560, #c62a47)', btn: 'Shop Shoes', cat: 'Shoes' },
  { title: '📚 Books Under $20', sub: 'Expand your mind, not your budget', bg: 'linear-gradient(135deg, #1a1a2e, #0f3460)', btn: 'Shop Books', cat: 'Books' },
];

const Home = ({ selectedCategory, searchQuery, onCategory }) => {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sort, setSort] = useState('default');
  const [bannerIdx, setBannerIdx] = useState(0);
  const [addedId, setAddedId] = useState(null);
  const { addToCart } = useCart();

  useEffect(() => {
    api.get('/products')
      .then(res => { setProducts(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    const timer = setInterval(() => setBannerIdx(i => (i + 1) % BANNERS.length), 4000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    let result = [...products];
    if (selectedCategory && selectedCategory !== 'All') {
      result = result.filter(p => p.category === selectedCategory);
    }
    if (searchQuery) {
      result = result.filter(p =>
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.category.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (sort === 'low') result.sort((a, b) => a.price - b.price);
    if (sort === 'high') result.sort((a, b) => b.price - a.price);
    if (sort === 'name') result.sort((a, b) => a.name.localeCompare(b.name));
    setFiltered(result);
  }, [searchQuery, selectedCategory, sort, products]);

  const getImage = (p) => {
    if (p.image && p.image.startsWith('http')) return p.image;
    return FALLBACK_IMAGES[p.category] || FALLBACK_IMAGES.default;
  };

  const renderStars = (rating) => {
    const r = Math.round(rating || 4);
    return '★'.repeat(r) + '☆'.repeat(5 - r);
  };

  const handleAddToCart = (p) => {
    addToCart(p);
    setAddedId(p._id);
    setTimeout(() => setAddedId(null), 1500);
  };

  const banner = BANNERS[bannerIdx];

  if (loading) return (
    <div style={styles.loadingPage}>
      <div style={styles.loadingBox}>
        <div style={styles.spinner}></div>
        <p style={styles.loadingText}>Loading Cartify...</p>
      </div>
    </div>
  );

  return (
    <div style={styles.page}>

      {/* Hero Banner */}
      <div style={{ ...styles.hero, background: banner.bg }}>
        <div style={styles.heroContent}>
          <p style={styles.heroBadge}>✨ Limited Time Offer</p>
          <h1 style={styles.heroTitle}>{banner.title}</h1>
          <p style={styles.heroSub}>{banner.sub}</p>
          <button style={styles.heroBtn} onClick={() => onCategory && onCategory(banner.cat)}>
            {banner.btn} →
          </button>
        </div>
        <div style={styles.heroDots}>
          {BANNERS.map((_, i) => (
            <button key={i} onClick={() => setBannerIdx(i)}
              style={i === bannerIdx ? styles.dotActive : styles.dot} />
          ))}
        </div>
      </div>

      {/* Filter Bar */}
      <div style={styles.filterBar}>
        <div style={styles.filterLeft}>
          <span style={styles.filterTitle}>
            {selectedCategory && selectedCategory !== 'All'
              ? `${selectedCategory}`
              : '🏠 All Products'}
          </span>
          <span style={styles.filterCount}>{filtered.length} items</span>
        </div>
        <div style={styles.filterRight}>
          <label style={styles.sortLabel}>Sort by:</label>
          <select value={sort} onChange={e => setSort(e.target.value)} style={styles.select}>
            <option value="default">Featured</option>
            <option value="low">Price: Low to High</option>
            <option value="high">Price: High to Low</option>
            <option value="name">Name: A-Z</option>
          </select>
        </div>
      </div>

      {/* Products Grid */}
      {filtered.length === 0 ? (
        <div style={styles.empty}>
          <p style={styles.emptyIcon}>😕</p>
          <h3>No products found</h3>
          <p style={{ color: '#888' }}>Try a different category or search term</p>
        </div>
      ) : (
        <div style={styles.grid}>
          {filtered.map(p => (
            <div key={p._id} style={styles.card}
              onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-4px)'}
              onMouseLeave={e => e.currentTarget.style.transform = 'translateY(0)'}
            >
              <Link to={`/product/${p._id}`} style={{ textDecoration: 'none' }}>
                <div style={styles.imgWrapper}>
                  <img
                    src={getImage(p)}
                    alt={p.name}
                    style={styles.img}
                    onError={e => { e.target.src = FALLBACK_IMAGES[p.category] || FALLBACK_IMAGES.default; }}
                  />
                  {p.stock === 0 && <div style={styles.outOfStockOverlay}>Out of Stock</div>}
                  {p.stock > 0 && p.stock < 10 && (
                    <span style={styles.lowStockBadge}>Only {p.stock} left!</span>
                  )}
                  <span style={styles.discountBadge}>17% OFF</span>
                </div>
              </Link>
              <div style={styles.cardBody}>
                <span style={styles.cardCategory}>{p.category}</span>
                <Link to={`/product/${p._id}`} style={styles.cardTitle}>{p.name}</Link>
                <div style={styles.starsRow}>
                  <span style={styles.stars}>{renderStars(p.rating)}</span>
                  <span style={styles.reviewCount}>({p.numReviews || 0})</span>
                </div>
                <div style={styles.priceRow}>
                  <span style={styles.price}>${p.price}</span>
                  <span style={styles.originalPrice}>${(p.price * 1.2).toFixed(0)}</span>
                </div>
                <p style={styles.freeDelivery}>🚚 FREE Delivery</p>
                <button
                  onClick={() => handleAddToCart(p)}
                  disabled={p.stock === 0}
                  style={
                    p.stock === 0 ? styles.disabledBtn
                    : addedId === p._id ? styles.addedBtn
                    : styles.addBtn
                  }
                >
                  {p.stock === 0 ? 'Out of Stock'
                    : addedId === p._id ? '✅ Added!'
                    : '🛒 Add to Cart'}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Footer */}
      <div style={styles.footer}>
        <div style={styles.footerGrid}>
          <div style={styles.footerCol}>
            <h3 style={styles.footerBrand}>🛒 Cartify</h3>
            <p style={styles.footerText}>Your one-stop shop for everything you love. Quality products, best prices.</p>
          </div>
          <div style={styles.footerCol}>
            <h4 style={styles.footerHead}>Quick Links</h4>
            <Link to="/" style={styles.footerLink}>Home</Link>
            <Link to="/cart" style={styles.footerLink}>Cart</Link>
            <Link to="/orders" style={styles.footerLink}>My Orders</Link>
          </div>
          <div style={styles.footerCol}>
            <h4 style={styles.footerHead}>Categories</h4>
            <span style={styles.footerLink}>Electronics</span>
            <span style={styles.footerLink}>Clothing</span>
            <span style={styles.footerLink}>Books</span>
            <span style={styles.footerLink}>Sports</span>
          </div>
          <div style={styles.footerCol}>
            <h4 style={styles.footerHead}>We Accept</h4>
            <p style={styles.footerText}>💳 Credit/Debit Cards</p>
            <p style={styles.footerText}>📱 UPI Payments</p>
            <p style={styles.footerText}>🏦 Net Banking</p>
            <p style={styles.footerText}>💵 Cash on Delivery</p>
          </div>
        </div>
        <div style={styles.footerBottom}>
          <p>© 2026 Cartify. All rights reserved. Made with ❤️</p>
        </div>
      </div>

    </div>
  );
};

const styles = {
  page: { background: '#f5f5f5', minHeight: '100vh' },
  loadingPage: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '80vh' },
  loadingBox: { textAlign: 'center' },
  spinner: { width: '48px', height: '48px', border: '4px solid #eee', borderTop: '4px solid #e94560', borderRadius: '50%', margin: '0 auto 16px' },
  loadingText: { color: '#888', fontSize: '16px' },
  hero: { padding: '70px 48px', position: 'relative', overflow: 'hidden', minHeight: '280px', display: 'flex', flexDirection: 'column', justifyContent: 'center' },
  heroContent: { maxWidth: '600px' },
  heroBadge: { display: 'inline-block', background: 'rgba(255,255,255,0.15)', color: '#fff', padding: '6px 16px', borderRadius: '20px', fontSize: '13px', marginBottom: '16px' },
  heroTitle: { fontSize: '42px', fontWeight: '800', color: '#fff', margin: '0 0 12px', lineHeight: '1.2' },
  heroSub: { fontSize: '18px', color: 'rgba(255,255,255,0.8)', margin: '0 0 28px' },
  heroBtn: { padding: '14px 32px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '30px', cursor: 'pointer', fontSize: '16px', fontWeight: '700', boxShadow: '0 4px 20px rgba(233,69,96,0.4)' },
  heroDots: { position: 'absolute', bottom: '20px', left: '48px', display: 'flex', gap: '8px' },
  dot: { width: '8px', height: '8px', borderRadius: '50%', background: 'rgba(255,255,255,0.4)', border: 'none', cursor: 'pointer' },
  dotActive: { width: '24px', height: '8px', borderRadius: '4px', background: '#fff', border: 'none', cursor: 'pointer' },
  filterBar: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 32px', background: '#fff', margin: '16px 0 0', boxShadow: '0 1px 4px rgba(0,0,0,0.05)', flexWrap: 'wrap', gap: '12px' },
  filterLeft: { display: 'flex', alignItems: 'center', gap: '12px' },
  filterTitle: { fontSize: '20px', fontWeight: '700', color: '#1a1a2e' },
  filterCount: { background: '#f0f0f0', padding: '4px 12px', borderRadius: '20px', fontSize: '13px', color: '#666' },
  filterRight: { display: 'flex', alignItems: 'center', gap: '10px' },
  sortLabel: { fontSize: '14px', color: '#666' },
  select: { padding: '8px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', background: '#fff', cursor: 'pointer', outline: 'none' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(230px, 1fr))', gap: '20px', padding: '20px 32px 40px' },
